module RefModule (
    input clk,
    input rst,
    input din,
    output reg [1:0] dout
);
    reg [1:0] unused_counter;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            dout <= 2'b00;
            unused_counter <= 2'b00;
        end else begin
            if (unused_counter == 2'b01) begin
                dout <= {din, din}; // Convert 1-bit to 2-bit
                unused_counter <= 2'b00;
            end else begin
                dout <= dout; // Hold the value
                unused_counter <= unused_counter + 1;
            end
        end
    end
endmodule
